/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    // 1. Calculate frequencies of all characters
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    const getMirror = (char) => {
        if (char >= 'a' && char <= 'z') {
            // Letter: 'a' -> 'z', 'b' -> 'y', ...
            // Position from 'a' (0-indexed): char.charCodeAt(0) - 'a'.charCodeAt(0)
            // Mirror position from 'z' (0-indexed): 25 - (char.charCodeAt(0) - 'a'.charCodeAt(0))
            // Mirror char code: 'z'.charCodeAt(0) - (25 - position)
            const charCode = char.charCodeAt(0);
            const baseA = 'a'.charCodeAt(0);
            const mirrorCode = 'z'.charCodeAt(0) - (charCode - baseA);
            return String.fromCharCode(mirrorCode);
        } else if (char >= '0' && char <= '9') {
            // Digit: '0' -> '9', '1' -> '8', ...
            // Position (0-indexed): char.charCodeAt(0) - '0'.charCodeAt(0)
            // Mirror position from '9': 9 - position
            // Mirror char code: '9'.charCodeAt(0) - (position)
            const charCode = char.charCodeAt(0);
            const base0 = '0'.charCodeAt(0);
            const mirrorCode = '9'.charCodeAt(0) - (charCode - base0);
            return String.fromCharCode(mirrorCode);
        }
        return null; // Should not happen based on constraints
    };

    let totalDifferenceSum = 0;
    const processedPairs = new Set();

    // 2. Iterate over unique characters found in the string
    for (const c of freqMap.keys()) {
        const m = getMirror(c);

        if (m === null) continue;

        // Ensure we only process a pair (c, m) once.
        // We canonicalize the pair by sorting lexicographically.
        const pairKey = [c, m].sort().join(',');

        if (processedPairs.has(pairKey)) {
            continue;
        }

        // The pair (c, m) has not been processed.
        processedPairs.add(pairKey);

        const freqC = freqMap.get(c) || 0;
        const freqM = freqMap.get(m) || 0;

        // Calculate the absolute difference
        const difference = Math.abs(freqC - freqM);

        totalDifferenceSum += difference;
    }

    return totalDifferenceSum;
}

