using namespace std;

/**
 * Helper function to get the mirror character based on the rules.
 */
char getMirrorChar(char c) {
    if (c >= 'a' && c <= 'z') {
        // Letter: 'a' -> 'z', 'b' -> 'y', ...
        // 'a' is 0, 'z' is 25. Mirror of i is 25 - i.
        int position = c - 'a';
        int mirrorPosition = 25 - position;
        return 'a' + mirrorPosition;
    } else if (c >= '0' && c <= '9') {
        // Digit: '0' -> '9', '1' -> '8', ...
        // '0' is 0, '9' is 9. Mirror of i is 9 - i.
        int position = c - '0';
        int mirrorPosition = 9 - position;
        return '0' + mirrorPosition;
    }
    return '\0'; // Should not happen
}

long long solve(std::string s) {
    // 1. Calculate frequencies of all characters
    std::map<char, int> freqMap;
    for (char c : s) {
        freqMap[c]++;
    }

    long long totalDifferenceSum = 0;
    std::set<char> processedChars;

    // 2. Iterate over unique characters found in the string
    for (const auto& pair : freqMap) {
        char c = pair.first;

        if (processedChars.count(c)) {
            continue;
        }

        char m = getMirrorChar(c);

        // m must be a valid character since c is in s and s only contains letters/digits

        // Check if c == m (e.g., 'm' <-> 'n' is not symmetric in terms of self-mirroring unless c is its own mirror, which only happens if c is the center of the alphabet/digits, e.g., 'm'/'n' in some contexts, but here: a<->z, m<->n, 0<->9. No character is its own mirror.)
        // Let's check the self-mirroring case explicitly.
        if (c == m) {
            // This case is impossible given the mirroring rules:
            // Letter: a (0) -> z (25). Only possible if 2*i = 25 (impossible)
            // Digit: 0 (0) -> 9 (9). Only possible if 2*i = 9 (impossible)
            // Still, if it were possible, we'd calculate the difference and mark c as processed.
            // For safety/completeness, we handle it, although it won't be hit.
            int freqC = freqMap[c];
            int freqM = freqMap[m];
            totalDifferenceSum += std::abs(freqC - freqM);
            processedChars.insert(c);
            continue;
        }

        // Process the pair (c, m) only once. We rely on the set to track processed characters.

        // If m was not in the string, freqMap[m] will return 0 via .count() check or direct map access if we used []
        // Using .count() check on freqMap before access is safer if we want to ensure we only iterate over chars present in s, 
        // but since we are iterating over freqMap.keys(), c is present. We need freq(m).
        int freqC = freqMap[c];
        int freqM = freqMap.count(m) ? freqMap.at(m) : 0;

        // Calculate the absolute difference for this pair (c, m)
        long long difference = std::abs((long long)freqC - freqM);
        totalDifferenceSum += difference;

        // Mark both c and m as processed to avoid recounting when the loop hits m
        processedChars.insert(c);
        processedChars.insert(m);
    }

    return totalDifferenceSum;
}

