        if (m == '\0') continue; // Should not happen based on constraints

        // Create the canonical pair (smaller, larger)
        char c1 = std::min(c, m);
        char c2 = std::max(c, m);
        std::pair<char, char> currentPair = {c1, c2};

        if (processedPairs.count(currentPair)) {
            continue;
        }

        // The pair (c, m) has not been processed.
        processedPairs.insert(currentPair);

        // Get frequencies (using 0 if the mirror character is not in the string)
        int freqC = freqMap.count(c) ? freqMap[c] : 0;
        int freqM = freqMap.count(m) ? freqMap[m] : 0;

        // Calculate the absolute difference
        long long difference = std::abs(freqC - freqM);

        totalDifferenceSum += difference;
    }

    return totalDifferenceSum;
}
